/* CISSP :: content/quiz6.js — CISSP Domain 6 question bank (100 items). */
window.CISSP = window.CISSP || {}; CISSP.questions = CISSP.questions || [];
CISSP.questions.push(
{ id:"D6-001", domain:6, obj:"6.1", diff:"easy", q:"A CISO is establishing a security testing program and wants to ensure the strategy verifies that controls satisfy stated objectives rather than merely running scans. What is the PRIMARY purpose of a security assessment and testing strategy?", options:["To document which security tools the organization has purchased","To satisfy the auditor so findings can be closed quickly","To validate that security controls are designed and operating effectively to meet objectives","To replace the need for a formal risk assessment"], answer:2, explain:"<strong>To validate that security controls are designed and operating effectively to meet objectives</strong> is the core purpose of an assessment and testing strategy; it ties testing activities back to control objectives and risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To document which security tools the organization has purchased</b>: an inventory of tools is not the purpose of a testing strategy.</span><span class='qd'><b>To satisfy the auditor so findings can be closed quickly</b>: closing findings quickly is not a valid objective and can mask real risk.</span><span class='qd'><b>To replace the need for a formal risk assessment</b>: testing complements risk assessment; it does not replace it.</span>" },
{ id:"D6-002", domain:6, obj:"6.1", diff:"easy", q:"An organization must decide how often to test critical controls. Which factor should MOST influence the frequency of security control testing?", options:["The calendar quarter in which the budget resets","The personal preference of the system administrator","The number of vendors that offer scanning tools","The risk the control mitigates and the rate of change in the environment"], answer:3, explain:"<strong>The risk the control mitigates and the rate of change in the environment</strong> drives testing cadence; higher-risk, frequently changing systems warrant more frequent testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The calendar quarter in which the budget resets</b>: budget cycles are administrative and do not reflect risk.</span><span class='qd'><b>The personal preference of the system administrator</b>: individual preference is not a risk-based driver.</span><span class='qd'><b>The number of vendors that offer scanning tools</b>: tool availability does not determine how often controls must be tested.</span>" },
{ id:"D6-003", domain:6, obj:"6.1", diff:"medium", q:"A security manager wants to know which activity provides the BROADEST evaluation, including people, processes, and technology rather than only technical flaws.", options:["A vulnerability scan","A security assessment","A port scan","A penetration test"], answer:1, explain:"<strong>A security assessment</strong> is a broad evaluation that examines people, processes, and technology, often incorporating interviews, document review, and technical testing to judge overall control effectiveness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A vulnerability scan</b>: a scan is a narrow technical activity that finds known flaws, not a holistic evaluation.</span><span class='qd'><b>A port scan</b>: a port scan only enumerates open ports and services.</span><span class='qd'><b>A penetration test</b>: a pen test is a focused exploitation exercise, narrower than a full assessment.</span>" },
{ id:"D6-004", domain:6, obj:"6.1", diff:"medium", q:"An auditor and a security team dispute the difference between an assessment and an audit. Which statement BEST distinguishes a security audit from a security assessment?", options:["An audit is a formal, evidence-based verification against a defined standard, often by an independent party","An audit is always automated while an assessment is always manual","An assessment produces a legally binding attestation while an audit does not","An audit only checks physical controls while an assessment only checks technical ones"], answer:0, explain:"<strong>An audit is a formal, evidence-based verification against a defined standard, often by an independent party</strong>; its defining traits are formality, evidence, an authoritative standard, and independence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An audit is always automated while an assessment is always manual</b>: both can use manual and automated methods.</span><span class='qd'><b>An assessment produces a legally binding attestation while an audit does not</b>: it is audits that typically produce formal attestations, so this is reversed.</span><span class='qd'><b>An audit only checks physical controls while an assessment only checks technical ones</b>: neither is limited to a single control category.</span>" },
{ id:"D6-005", domain:6, obj:"6.1", diff:"hard", q:"A new CISO finds testing is done ad hoc by individual teams with no shared scope, cadence, or reporting. What should the CISO establish FIRST to bring order to the program?", options:["Purchase an enterprise vulnerability scanner for every team","Hire an external penetration testing firm for an immediate engagement","Define a formal assessment and testing strategy aligned to risk and business objectives","Require every server to be scanned nightly"], answer:2, explain:"<strong>Define a formal assessment and testing strategy aligned to risk and business objectives</strong> comes first; the strategy establishes scope, cadence, roles, and reporting so subsequent activities are coordinated and risk-driven.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Purchase an enterprise vulnerability scanner for every team</b>: buying tools before defining strategy leads to uncoordinated tool sprawl.</span><span class='qd'><b>Hire an external penetration testing firm for an immediate engagement</b>: a point engagement without a strategy is premature and not repeatable.</span><span class='qd'><b>Require every server to be scanned nightly</b>: a blanket rule ignores risk prioritization and strategy.</span>" },
{ id:"D6-006", domain:6, obj:"6.1", diff:"easy", q:"Management asks who should ideally perform an assessment intended to give an objective, unbiased opinion on control effectiveness. Which party BEST provides that independence?", options:["The team that built and operates the control","The vendor that sold the control product","The help desk that supports end users","An independent internal audit function or external assessor"], answer:3, explain:"<strong>An independent internal audit function or external assessor</strong> provides objectivity because they are separate from the group that designed or operates the control, reducing conflict of interest.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The team that built and operates the control</b>: self-assessment by the owning team lacks independence.</span><span class='qd'><b>The vendor that sold the control product</b>: the vendor has a commercial interest in a favorable result.</span><span class='qd'><b>The help desk that supports end users</b>: the help desk lacks the mandate and independence to judge control effectiveness.</span>" },
{ id:"D6-007", domain:6, obj:"6.1", diff:"medium", q:"Before commissioning any test, a project sponsor asks what the FIRST step in scoping a security assessment should be. Which action best fits?", options:["Begin scanning the largest subnet immediately","Assign CVSS scores to every host on the network","Identify the assets, objectives, and rules of engagement to be covered","Draft the final report template"], answer:2, explain:"<strong>Identify the assets, objectives, and rules of engagement to be covered</strong> defines scope first, ensuring the effort targets the right systems within agreed boundaries and legal authority.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Begin scanning the largest subnet immediately</b>: scanning before scope is set risks touching out-of-bounds systems and wasting effort.</span><span class='qd'><b>Assign CVSS scores to every host on the network</b>: scoring is a later analysis activity, not a scoping step.</span><span class='qd'><b>Draft the final report template</b>: reporting format is prepared later and does not define scope.</span>" },
{ id:"D6-008", domain:6, obj:"6.1", diff:"hard", q:"A regulated firm must show regulators that its testing program is repeatable and defensible year over year. Which characteristic of the strategy MOST supports this need?", options:["Testing performed only when a breach is suspected","Rotating testers so no one repeats a technique","A documented, standards-aligned methodology with defined metrics and evidence retention","Relying on each engineer's individual judgment"], answer:2, explain:"<strong>A documented, standards-aligned methodology with defined metrics and evidence retention</strong> makes the program repeatable and defensible, letting regulators trace consistent, evidence-backed testing across cycles.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Testing performed only when a breach is suspected</b>: reactive-only testing is neither repeatable nor proactive.</span><span class='qd'><b>Rotating testers so no one repeats a technique</b>: rotation for its own sake harms consistency and comparability.</span><span class='qd'><b>Relying on each engineer's individual judgment</b>: undocumented judgment cannot be reproduced or defended to regulators.</span>" },
{ id:"D6-009", domain:6, obj:"6.1", diff:"medium", q:"During strategy design, the team debates when to test controls in the system lifecycle. Integrating security testing EARLY and continuously throughout the SDLC is BEST described as which principle?", options:["Shift-left / continuous testing","Defense in depth","Separation of duties","Least privilege"], answer:0, explain:"<strong>Shift-left / continuous testing</strong> means moving testing earlier and performing it continuously so defects are caught cheaply before release and controls are validated throughout the lifecycle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Defense in depth</b>: layering controls is about architecture, not the timing of testing.</span><span class='qd'><b>Separation of duties</b>: separating conflicting tasks is an access-control concept, not a testing cadence.</span><span class='qd'><b>Least privilege</b>: limiting access rights is unrelated to when testing occurs.</span>" },
{ id:"D6-010", domain:6, obj:"6.1", diff:"easy", q:"A security leader wants a single artifact that maps each control to how, how often, and by whom it will be tested. Which document BEST serves this purpose?", options:["A test plan / assessment plan","A network diagram","An incident response runbook","A data flow diagram"], answer:0, explain:"<strong>A test plan / assessment plan</strong> documents the scope, methods, schedule, responsible parties, and success criteria for testing each control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A network diagram</b>: a diagram shows topology, not the testing approach for controls.</span><span class='qd'><b>An incident response runbook</b>: a runbook guides response after an incident, not planned control testing.</span><span class='qd'><b>A data flow diagram</b>: a data flow diagram maps how data moves, not how controls are tested.</span>" },
{ id:"D6-011", domain:6, obj:"6.1", diff:"easy", q:"An organization aligns its testing methodology to a recognized framework so results are comparable and credible. Which of the following is such a testing/assessment framework?", options:["The OSI reference model","RAID storage levels","NIST SP 800-115","The TCP three-way handshake"], answer:2, explain:"<strong>NIST SP 800-115</strong> is the Technical Guide to Information Security Testing and Assessment, a recognized methodology for planning and conducting security testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The OSI reference model</b>: OSI is a networking layering model, not a testing framework.</span><span class='qd'><b>RAID storage levels</b>: RAID concerns disk redundancy, not security assessment.</span><span class='qd'><b>The TCP three-way handshake</b>: the handshake is a connection mechanism, not an assessment methodology.</span>" },
{ id:"D6-012", domain:6, obj:"6.1", diff:"hard", q:"A CISO must justify testing spend to the board. Which framing BEST reflects the CISSP risk-owner altitude for prioritizing what to test?", options:["Prioritize testing on assets and controls tied to the highest business risk","Test everything equally to be thorough and fair","Test whatever the newest tool can scan","Let each department decide independently what matters"], answer:0, explain:"<strong>Prioritize testing on assets and controls tied to the highest business risk</strong> reflects risk-based governance; finite resources are directed where a control failure would most harm the business.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Test everything equally to be thorough and fair</b>: equal treatment ignores that risks differ and wastes resources.</span><span class='qd'><b>Test whatever the newest tool can scan</b>: tool capability, not risk, would drive scope.</span><span class='qd'><b>Let each department decide independently what matters</b>: uncoordinated local decisions miss enterprise-level risk.</span>" },
{ id:"D6-013", domain:6, obj:"6.1", diff:"easy", q:"An assessment strategy specifies that testers must not access production customer data during testing. This constraint is documented in which part of the engagement?", options:["The rules of engagement","The CVSS vector","The exit interview","The remediation ticket"], answer:0, explain:"<strong>The rules of engagement</strong> define the authorized scope, boundaries, timing, and constraints such as prohibiting access to production customer data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The CVSS vector</b>: a CVSS vector scores a vulnerability's severity, not engagement constraints.</span><span class='qd'><b>The exit interview</b>: the exit interview reports results after testing, not the up-front constraints.</span><span class='qd'><b>The remediation ticket</b>: a ticket tracks fixing a finding, not testing boundaries.</span>" },
{ id:"D6-014", domain:6, obj:"6.1", diff:"medium", q:"To validate that a testing strategy remains fit for purpose, management reviews it periodically. What is the MAIN reason to reassess and update the strategy over time?", options:["Auditors dislike documents that never change","Updating documents increases the page count for compliance","Old strategies automatically expire after one year by law","Threats, technology, and business objectives evolve, so the strategy must stay aligned to current risk"], answer:3, explain:"<strong>Threats, technology, and business objectives evolve, so the strategy must stay aligned to current risk</strong>; periodic review keeps the program relevant and effective.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Auditors dislike documents that never change</b>: auditor preference is not the substantive reason.</span><span class='qd'><b>Updating documents increases the page count for compliance</b>: volume is not the goal; relevance is.</span><span class='qd'><b>Old strategies automatically expire after one year by law</b>: no universal law mandates a one-year expiry.</span>" },
{ id:"D6-015", domain:6, obj:"6.1", diff:"easy", q:"A company wants assurance that a control is not only designed correctly but is actually working in production. Testing whether a control operates effectively over time is known as testing its:", options:["Operating effectiveness","Design adequacy only","Purchase price","Vendor reputation"], answer:0, explain:"<strong>Operating effectiveness</strong> testing verifies that a properly designed control functions as intended over a period, not just that it looks correct on paper.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Design adequacy only</b>: design testing checks whether the control could work, not that it does over time.</span><span class='qd'><b>Purchase price</b>: cost is unrelated to whether a control operates effectively.</span><span class='qd'><b>Vendor reputation</b>: reputation does not demonstrate the control works in this environment.</span>" },
{ id:"D6-016", domain:6, obj:"6.1", diff:"hard", q:"A cloud-hosted application is jointly secured by the customer and the cloud provider. When designing the test strategy, what must the customer confirm FIRST regarding provider-managed layers?", options:["That the customer may exploit provider infrastructure at will","The shared responsibility boundaries and provider testing permissions and constraints","That the provider will accept liability for all findings","That the customer can disable provider logging during tests"], answer:1, explain:"<strong>The shared responsibility boundaries and provider testing permissions and constraints</strong> must be confirmed first so the customer tests only what it is responsible for and stays within contractual and legal limits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That the customer may exploit provider infrastructure at will</b>: providers restrict testing of their layers; unauthorized testing may breach contract or law.</span><span class='qd'><b>That the provider will accept liability for all findings</b>: liability terms are contractual and do not define test scope.</span><span class='qd'><b>That the customer can disable provider logging during tests</b>: disabling provider logging is generally not permitted and undermines evidence.</span>" },
{ id:"D6-017", domain:6, obj:"6.1", diff:"medium", q:"An organization maintains both automated and manual testing methods in its strategy. What is the PRIMARY advantage of including manual testing alongside automated tools?", options:["Manual testing is always cheaper than automation","Manual testing eliminates the need for documentation","Manual testing runs faster than any scanner","Skilled testers can find logic and business-context flaws that automated tools miss"], answer:3, explain:"<strong>Skilled testers can find logic and business-context flaws that automated tools miss</strong>, such as broken authorization or abuse of legitimate features, which pattern-based scanners typically overlook.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual testing is always cheaper than automation</b>: skilled manual effort is usually more expensive per test.</span><span class='qd'><b>Manual testing eliminates the need for documentation</b>: manual testing still requires documented methods and findings.</span><span class='qd'><b>Manual testing runs faster than any scanner</b>: automated scanners are generally faster at breadth.</span>" },
{ id:"D6-018", domain:6, obj:"6.1", diff:"medium", q:"A validation step in the strategy requires confirming that the testing program itself is producing accurate, complete results. Which activity BEST validates the assessment process?", options:["Counting how many scans were run last month","Increasing the number of testing tools","Asking staff if they feel secure","Periodic quality review comparing test findings against independent verification"], answer:3, explain:"<strong>Periodic quality review comparing test findings against independent verification</strong> validates that the process yields accurate and complete results, catching false negatives and gaps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Counting how many scans were run last month</b>: activity volume does not prove result quality.</span><span class='qd'><b>Increasing the number of testing tools</b>: more tools does not validate accuracy of results.</span><span class='qd'><b>Asking staff if they feel secure</b>: perception is not an objective measure of process accuracy.</span>" },
{ id:"D6-019", domain:6, obj:"6.2", diff:"easy", q:"A team wants to enumerate known missing patches and misconfigurations across hundreds of servers quickly, without exploiting anything. Which activity is MOST appropriate?", options:["A full penetration test with exploitation","A source code review","A tabletop exercise","A vulnerability assessment (scan)"], answer:3, explain:"<strong>A vulnerability assessment (scan)</strong> efficiently identifies known vulnerabilities and misconfigurations at scale without exploiting them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A full penetration test with exploitation</b>: a pen test actively exploits and is slower and narrower for broad enumeration.</span><span class='qd'><b>A source code review</b>: code review examines application source, not server patch levels across a fleet.</span><span class='qd'><b>A tabletop exercise</b>: a tabletop is a discussion-based drill, not technical vulnerability discovery.</span>" },
{ id:"D6-020", domain:6, obj:"6.2", diff:"medium", q:"A vulnerability scanner reports a critical flaw on a host, but manual investigation shows the vulnerable service is not actually present. This scanner result is BEST described as a:", options:["True positive","False positive","False negative","True negative"], answer:1, explain:"<strong>False positive</strong> describes a finding the tool reports as present that does not actually exist, requiring validation to avoid wasted remediation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>True positive</b>: a true positive is a real, correctly reported issue, which this is not.</span><span class='qd'><b>False negative</b>: a false negative is a real issue the tool missed, the opposite situation.</span><span class='qd'><b>True negative</b>: a true negative is correctly reporting no issue where none exists.</span>" },
{ id:"D6-021", domain:6, obj:"6.2", diff:"hard", q:"After a scan, an analyst is MOST concerned about a vulnerability that exists on a system but was NOT reported by the scanner. This missed vulnerability is a:", options:["False positive","True positive","False negative","Benign finding"], answer:2, explain:"<strong>False negative</strong> is the most dangerous scanner error because a real vulnerability goes unreported and therefore unremediated, leaving exposure the team is unaware of.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>False positive</b>: a false positive is a reported issue that is not real, which wastes effort but does not hide risk.</span><span class='qd'><b>True positive</b>: a true positive is correctly reported and is not a miss.</span><span class='qd'><b>Benign finding</b>: a benign finding is informational, not a missed vulnerability.</span>" },
{ id:"D6-022", domain:6, obj:"6.2", diff:"easy", q:"An organization must compare and prioritize vulnerabilities from many scans using a consistent severity score. Which standard provides that scoring?", options:["CVE by itself","OWASP Top 10","CVSS (Common Vulnerability Scoring System)","ISO 27001"], answer:2, explain:"<strong>CVSS (Common Vulnerability Scoring System)</strong> provides a standardized numeric severity score so vulnerabilities can be compared and prioritized consistently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>CVE by itself</b>: a CVE is an identifier for a specific vulnerability and does not itself provide a severity score.</span><span class='qd'><b>OWASP Top 10</b>: the OWASP Top 10 is an awareness list of web risk categories, not a per-finding scoring system.</span><span class='qd'><b>ISO 27001</b>: ISO 27001 is an ISMS standard, not a vulnerability scoring method.</span>" },
{ id:"D6-023", domain:6, obj:"6.2", diff:"easy", q:"A scanner is given valid credentials so it can log in and inspect installed software, registry, and patch levels from the inside. This is BEST described as a:", options:["Unauthenticated scan","Passive network tap","Credentialed (authenticated) scan","Denial-of-service test"], answer:2, explain:"<strong>Credentialed (authenticated) scan</strong> uses valid credentials to inspect a host from the inside, yielding more accurate and complete results than an external view.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unauthenticated scan</b>: an unauthenticated scan sees only the external surface and cannot inspect installed software.</span><span class='qd'><b>Passive network tap</b>: a passive tap observes traffic but does not log in to hosts.</span><span class='qd'><b>Denial-of-service test</b>: a DoS test measures availability under attack, not configuration inspection.</span>" },
{ id:"D6-024", domain:6, obj:"6.2", diff:"medium", q:"An organization wants to know not just whether vulnerabilities exist, but whether an attacker could actually chain them to reach sensitive data. Which activity BEST demonstrates real-world exploitability?", options:["A vulnerability scan","A patch inventory report","An asset discovery scan","A penetration test"], answer:3, explain:"<strong>A penetration test</strong> actively attempts to exploit and chain weaknesses to demonstrate real-world impact and reachability of sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A vulnerability scan</b>: a scan lists potential flaws but does not prove they can be exploited or chained.</span><span class='qd'><b>A patch inventory report</b>: an inventory shows missing patches, not exploitability.</span><span class='qd'><b>An asset discovery scan</b>: discovery finds hosts and services, not exploit paths.</span>" },
{ id:"D6-025", domain:6, obj:"6.2", diff:"medium", q:"In a penetration test where the tester is given NO prior knowledge of the environment and simulates an outside attacker, the engagement is BEST described as:", options:["Black-box testing","White-box testing","Gray-box testing","Regression testing"], answer:0, explain:"<strong>Black-box testing</strong> gives the tester no internal knowledge, simulating an external attacker who must discover the environment from scratch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>White-box testing</b>: white-box provides full internal knowledge such as source and architecture.</span><span class='qd'><b>Gray-box testing</b>: gray-box gives partial knowledge, more than none.</span><span class='qd'><b>Regression testing</b>: regression checks that changes did not break existing functionality, unrelated to attacker knowledge level.</span>" },
{ id:"D6-026", domain:6, obj:"6.2", diff:"medium", q:"A tester is provided full architecture diagrams, source code, and credentials to maximize coverage and efficiency of the assessment. This knowledge level is called:", options:["White-box","Black-box","Gray-box","Blind"], answer:0, explain:"<strong>White-box</strong> testing supplies full internal knowledge so the tester can examine every layer thoroughly and efficiently rather than spending time on discovery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Black-box</b>: black-box provides no internal knowledge.</span><span class='qd'><b>Gray-box</b>: gray-box provides only partial knowledge, not full source and diagrams.</span><span class='qd'><b>Blind</b>: blind testing withholds information from the tester and is closer to black-box.</span>" },
{ id:"D6-027", domain:6, obj:"6.2", diff:"hard", q:"An organization wants a realistic test where the offensive team attacks with limited knowledge while the defensive team is NOT told a test is occurring, to measure real detection and response. This is BEST described as:", options:["A white-box code review","A double-blind test","A credentialed vulnerability scan","A gray-box configuration audit"], answer:1, explain:"<strong>A double-blind test</strong> means neither the attackers have full knowledge nor are the defenders forewarned, providing the most realistic measure of detection and response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A white-box code review</b>: code review is static analysis of source, not a live attack-and-detect exercise.</span><span class='qd'><b>A credentialed vulnerability scan</b>: a credentialed scan enumerates flaws and does not test defender response.</span><span class='qd'><b>A gray-box configuration audit</b>: a configuration audit reviews settings, not real-time detection under attack.</span>" },
{ id:"D6-028", domain:6, obj:"6.2", diff:"easy", q:"In security testing team color conventions, the team that plays the ATTACKER and probes for weaknesses is the:", options:["Blue team","Red team","White team","Green team"], answer:1, explain:"<strong>Red team</strong> takes the adversarial role, emulating attackers to find and exploit weaknesses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Blue team</b>: the blue team defends and detects, not attacks.</span><span class='qd'><b>White team</b>: the white team referees and sets rules for an exercise.</span><span class='qd'><b>Green team</b>: green is not a standard attacker designation; it is sometimes tied to builders or automation.</span>" },
{ id:"D6-029", domain:6, obj:"6.2", diff:"easy", q:"The team responsible for DEFENDING systems, monitoring, and responding during a security exercise is the:", options:["Blue team","Red team","Purple team","Black team"], answer:0, explain:"<strong>Blue team</strong> defends the environment, operating monitoring and response to detect and stop the red team.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Red team</b>: the red team attacks rather than defends.</span><span class='qd'><b>Purple team</b>: purple coordinates red and blue collaboration; it is not the defender itself.</span><span class='qd'><b>Black team</b>: black team is not a standard defensive designation.</span>" },
{ id:"D6-030", domain:6, obj:"6.2", diff:"medium", q:"A CISO wants attackers and defenders to work together in real time so that every offensive technique immediately improves detection. Which approach BEST achieves this?", options:["A blind red-team engagement","An unauthenticated scan","Purple teaming","A tabletop-only exercise"], answer:2, explain:"<strong>Purple teaming</strong> integrates red and blue teams collaboratively so offensive findings are used immediately to tune and improve defensive detection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A blind red-team engagement</b>: a blind engagement deliberately withholds information from defenders, preventing real-time collaboration.</span><span class='qd'><b>An unauthenticated scan</b>: a scan does not involve collaborative attack-and-defend tuning.</span><span class='qd'><b>A tabletop-only exercise</b>: a tabletop is discussion-based and does not exercise live detection tuning.</span>" },
{ id:"D6-031", domain:6, obj:"6.2", diff:"medium", q:"A developer wants to analyze application SOURCE CODE for vulnerabilities without executing the program. Which technique is this?", options:["DAST (Dynamic Application Security Testing)","Fuzzing","Penetration testing of the running app","SAST (Static Application Security Testing)"], answer:3, explain:"<strong>SAST (Static Application Security Testing)</strong> inspects source code, bytecode, or binaries without running the application, catching flaws early in development.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DAST (Dynamic Application Security Testing)</b>: DAST tests a running application from the outside, not static source.</span><span class='qd'><b>Fuzzing</b>: fuzzing sends malformed input to a running program, which requires execution.</span><span class='qd'><b>Penetration testing of the running app</b>: pen testing exercises a live target, not static source analysis.</span>" },
{ id:"D6-032", domain:6, obj:"6.2", diff:"easy", q:"A security team tests a RUNNING web application by sending crafted requests and observing responses, without access to source code. This technique is:", options:["SAST","DAST","IAST configuration review","Manual code walkthrough"], answer:1, explain:"<strong>DAST</strong> examines a running application from the outside by sending inputs and analyzing responses, finding runtime and environment issues without source access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST</b>: SAST analyzes static source or binaries, not a live running app via requests.</span><span class='qd'><b>IAST configuration review</b>: IAST instruments the app internally during execution; a review of its config is not the described black-box request testing.</span><span class='qd'><b>Manual code walkthrough</b>: a walkthrough reads code, which the team here does not have.</span>" },
{ id:"D6-033", domain:6, obj:"6.2", diff:"hard", q:"A team wants continuous analysis that combines runtime observation with code-level insight by instrumenting the application from the inside as it runs. Which technique BEST fits?", options:["SAST","DAST","Port scanning","IAST (Interactive Application Security Testing)"], answer:3, explain:"<strong>IAST (Interactive Application Security Testing)</strong> instruments the application to observe execution from within, combining runtime behavior with code-level context for more precise findings.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST</b>: SAST is static and does not observe runtime behavior.</span><span class='qd'><b>DAST</b>: DAST observes from outside without internal code context.</span><span class='qd'><b>Port scanning</b>: port scanning enumerates services and has no application code insight.</span>" },
{ id:"D6-034", domain:6, obj:"6.2", diff:"medium", q:"A tester bombards an input field with large volumes of malformed, random, and unexpected data to trigger crashes or unhandled errors. This technique is called:", options:["Regression testing","Boundary documentation","Fuzzing","Threat modeling"], answer:2, explain:"<strong>Fuzzing</strong> feeds malformed or random inputs to a program to expose crashes, memory errors, and unhandled conditions that indicate vulnerabilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Regression testing</b>: regression verifies existing features still work, not deliberate malformed input attacks.</span><span class='qd'><b>Boundary documentation</b>: documenting boundaries is not an active testing technique.</span><span class='qd'><b>Threat modeling</b>: threat modeling is an analysis exercise, not input injection.</span>" },
{ id:"D6-035", domain:6, obj:"6.2", diff:"hard", q:"A fuzzing tool uses knowledge of the input's expected structure (for example, a file format's fields) to craft inputs that stay valid enough to reach deep code paths. This is BEST described as:", options:["Dumb (random) fuzzing","Generation-based / intelligent fuzzing","Regression fuzzing","Passive fuzzing"], answer:1, explain:"<strong>Generation-based / intelligent fuzzing</strong> uses a model of the input format to build structured but abnormal inputs, reaching deeper code paths than purely random data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Dumb (random) fuzzing</b>: dumb fuzzing mutates data blindly without format knowledge and often fails input validation early.</span><span class='qd'><b>Regression fuzzing</b>: this is not a standard category for structure-aware input generation.</span><span class='qd'><b>Passive fuzzing</b>: fuzzing is inherently active input injection, not passive.</span>" },
{ id:"D6-036", domain:6, obj:"6.2", diff:"easy", q:"During requirements analysis, a team documents how an attacker might deliberately ABUSE a feature to cause harm, capturing negative scenarios. This artifact is BEST described as a:", options:["Use case","Data flow diagram","Sequence diagram","Misuse case"], answer:3, explain:"<strong>Misuse case</strong> models hostile actor goals and how features could be abused, guiding security requirements and test cases for negative scenarios.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use case</b>: a use case describes intended, legitimate behavior, not abuse.</span><span class='qd'><b>Data flow diagram</b>: a data flow diagram maps data movement, not attacker abuse scenarios.</span><span class='qd'><b>Sequence diagram</b>: a sequence diagram shows message ordering, not misuse intent.</span>" },
{ id:"D6-037", domain:6, obj:"6.2", diff:"easy", q:"An organization must verify that two systems exchanging data through an API handle malformed, out-of-range, and unexpected values safely at their connection points. This is BEST described as:", options:["Physical security testing","Awareness training","Interface testing","Backup restoration"], answer:2, explain:"<strong>Interface testing</strong> validates the boundaries where components or systems connect, ensuring APIs and integrations handle valid and invalid inputs correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical security testing</b>: physical testing checks facilities, not software interfaces.</span><span class='qd'><b>Awareness training</b>: training educates users and does not test interfaces.</span><span class='qd'><b>Backup restoration</b>: restoration verifies recoverability, not interface robustness.</span>" },
{ id:"D6-038", domain:6, obj:"6.2", diff:"hard", q:"A mature SOC wants to continuously and automatically emulate known adversary techniques against production defenses to confirm detections still fire. Which capability BEST provides this?", options:["A one-time annual penetration test","Breach and Attack Simulation (BAS)","Static code analysis","A user awareness quiz"], answer:1, explain:"<strong>Breach and Attack Simulation (BAS)</strong> continuously and safely emulates real adversary techniques against live controls to validate that prevention and detection remain effective.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A one-time annual penetration test</b>: an annual test is a point-in-time snapshot, not continuous validation.</span><span class='qd'><b>Static code analysis</b>: SAST reviews code, not live control detections.</span><span class='qd'><b>A user awareness quiz</b>: a quiz measures knowledge, not technical detection efficacy.</span>" },
{ id:"D6-039", domain:6, obj:"6.2", diff:"medium", q:"After a penetration test proves a vulnerability is exploitable, what is the tester's NEXT appropriate action under the rules of engagement in a professional engagement?", options:["Document the finding and evidence, then continue within agreed scope or report as required","Immediately publish the exploit publicly","Delete logs to hide the activity","Leave a permanent backdoor for future access"], answer:0, explain:"<strong>Document the finding and evidence, then continue within agreed scope or report as required</strong> is the professional next step; evidence supports remediation and the tester respects the rules of engagement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately publish the exploit publicly</b>: public disclosure without coordination is irresponsible and often violates the contract.</span><span class='qd'><b>Delete logs to hide the activity</b>: destroying evidence undermines the engagement and may be illegal.</span><span class='qd'><b>Leave a permanent backdoor for future access</b>: planting backdoors is unethical and exceeds authorized scope.</span>" },
{ id:"D6-040", domain:6, obj:"6.2", diff:"medium", q:"A penetration test methodology commonly follows a set of phases. Which sequence reflects the CORRECT general order?", options:["Exploitation, reconnaissance, planning, reporting","Planning/scoping, reconnaissance, scanning/enumeration, exploitation, reporting","Reporting, exploitation, scoping, cleanup","Scanning, cleanup, planning, reconnaissance"], answer:1, explain:"<strong>Planning/scoping, reconnaissance, scanning/enumeration, exploitation, reporting</strong> reflects the standard progression from authorization and information gathering through active attack to documented results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Exploitation, reconnaissance, planning, reporting</b>: exploiting before planning and recon is out of order and unauthorized.</span><span class='qd'><b>Reporting, exploitation, scoping, cleanup</b>: reporting cannot precede the testing that produces the findings.</span><span class='qd'><b>Scanning, cleanup, planning, reconnaissance</b>: cleanup and scanning before planning and recon is illogical.</span>" },
{ id:"D6-041", domain:6, obj:"6.2", diff:"hard", q:"An organization's SAST tool flags hundreds of issues, many of which are not exploitable in the deployed configuration. To make the program effective, what should the team do?", options:["Triage findings using context, combine SAST with DAST/IAST, and tune rules to cut false positives","Ignore all SAST output as unreliable","Fix every flagged line regardless of context","Disable the tool to avoid noise"], answer:0, explain:"<strong>Triage findings using context, combine SAST with DAST/IAST, and tune rules to cut false positives</strong> turns raw output into actionable, validated findings, using runtime techniques to confirm exploitability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore all SAST output as unreliable</b>: discarding all output loses genuine findings.</span><span class='qd'><b>Fix every flagged line regardless of context</b>: fixing non-exploitable noise wastes effort and delays real fixes.</span><span class='qd'><b>Disable the tool to avoid noise</b>: removing the tool eliminates its value rather than tuning it.</span>" },
{ id:"D6-042", domain:6, obj:"6.2", diff:"medium", q:"A tester wants to identify which live hosts, open ports, and services exist before deeper testing. Which activity comes FIRST and provides this map?", options:["Exploitation","Report writing","Remediation validation","Reconnaissance and enumeration (discovery/scanning)"], answer:3, explain:"<strong>Reconnaissance and enumeration (discovery/scanning)</strong> maps live hosts, open ports, and services, providing the attack surface picture needed before targeted testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Exploitation</b>: exploitation comes after the attack surface is understood.</span><span class='qd'><b>Report writing</b>: reporting happens after testing produces findings.</span><span class='qd'><b>Remediation validation</b>: validating fixes occurs after findings are reported and addressed.</span>" },
{ id:"D6-043", domain:6, obj:"6.2", diff:"medium", q:"A financial application must be tested for logic flaws such as manipulating a checkout to receive negative-price refunds. Which testing approach is MOST likely to catch this?", options:["Manual penetration testing with business-logic focus","An automated signature-based vulnerability scan","A port scan","A patch compliance report"], answer:0, explain:"<strong>Manual penetration testing with business-logic focus</strong> is best at uncovering application logic abuse, because such flaws depend on context that automated signatures do not model.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An automated signature-based vulnerability scan</b>: signature scanners detect known technical flaws, not novel business-logic abuse.</span><span class='qd'><b>A port scan</b>: a port scan only enumerates services.</span><span class='qd'><b>A patch compliance report</b>: patch status is unrelated to application logic flaws.</span>" },
{ id:"D6-044", domain:6, obj:"6.2", diff:"easy", q:"Which of the following BEST describes the goal of a red team engagement compared with a standard vulnerability assessment?", options:["To emulate a realistic adversary and test detection and response, not just find flaws","To catalog every missing patch","To generate CVSS scores automatically","To review firewall rule syntax"], answer:0, explain:"<strong>To emulate a realistic adversary and test detection and response, not just find flaws</strong> captures the red team's purpose: measuring how well the organization detects and responds to a determined attacker.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To catalog every missing patch</b>: cataloging patches is a vulnerability-assessment task, not the red team goal.</span><span class='qd'><b>To generate CVSS scores automatically</b>: scoring is a scanning output, not adversary emulation.</span><span class='qd'><b>To review firewall rule syntax</b>: rule review is a configuration audit task.</span>" },
{ id:"D6-045", domain:6, obj:"6.2", diff:"medium", q:"A DevSecOps pipeline should catch insecure code as early as possible. Where is SAST MOST effectively integrated?", options:["Only after production deployment","Only during the annual audit","Into the CI pipeline so code is scanned on each commit or build","Only when a breach occurs"], answer:2, explain:"<strong>Into the CI pipeline so code is scanned on each commit or build</strong> embodies shift-left; developers get immediate feedback and defects are caught before release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only after production deployment</b>: post-deployment scanning is far too late to be cheap or preventive.</span><span class='qd'><b>Only during the annual audit</b>: annual-only scanning misses code introduced throughout the year.</span><span class='qd'><b>Only when a breach occurs</b>: reactive scanning after a breach defeats the preventive purpose.</span>" },
{ id:"D6-046", domain:6, obj:"6.2", diff:"medium", q:"During a test, an application crashes when a text field receives 10,000 characters, revealing a possible buffer overflow. Which testing technique MOST likely produced this crash?", options:["Fuzzing","Threat modeling","Access recertification","Log review"], answer:0, explain:"<strong>Fuzzing</strong> sends oversized and malformed inputs like an over-length string, commonly triggering crashes that reveal memory-handling flaws such as buffer overflows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Threat modeling</b>: threat modeling is analytical and does not send live inputs.</span><span class='qd'><b>Access recertification</b>: recertification reviews entitlements, not input handling.</span><span class='qd'><b>Log review</b>: reviewing logs analyzes past events rather than injecting inputs.</span>" },
{ id:"D6-047", domain:6, obj:"6.2", diff:"hard", q:"A CISO wants to know whether the organization's EDR and SIEM would actually detect a credential-dumping technique used by a known threat group, without waiting a year for the next red team. Which is the MOST efficient option?", options:["A targeted breach and attack simulation of that specific technique","A full black-box penetration test","A password policy review","A user awareness campaign"], answer:0, explain:"<strong>A targeted breach and attack simulation of that specific technique</strong> safely and repeatably exercises the exact technique against live controls, quickly confirming whether EDR and SIEM detect it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A full black-box penetration test</b>: a full engagement is broader and slower than validating one specific technique.</span><span class='qd'><b>A password policy review</b>: policy review does not test detection of the live technique.</span><span class='qd'><b>A user awareness campaign</b>: awareness training does not measure EDR/SIEM detection.</span>" },
{ id:"D6-048", domain:6, obj:"6.2", diff:"medium", q:"An external assessor is authorized to test the organization's internet-facing systems from the public internet. This engagement is BEST classified as:", options:["An internal vulnerability assessment","An external penetration test","A physical penetration test","A configuration audit"], answer:1, explain:"<strong>An external penetration test</strong> attacks internet-facing systems from outside the perimeter, evaluating the exposure a remote attacker would face.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An internal vulnerability assessment</b>: internal testing originates from inside the network, not the public internet.</span><span class='qd'><b>A physical penetration test</b>: physical testing targets facilities and access controls, not remote network exposure.</span><span class='qd'><b>A configuration audit</b>: a configuration audit reviews settings rather than actively attacking from outside.</span>" },
{ id:"D6-049", domain:6, obj:"6.2", diff:"hard", q:"During interface testing of a microservices system, a tester finds one service trusts another's input without validation, so a compromised service can inject malicious data downstream. Which principle is MOST directly violated?", options:["Never trust input, even from internal components (validate at boundaries)","Availability over confidentiality","Security through obscurity","Single point of failure elimination"], answer:0, explain:"<strong>Never trust input, even from internal components (validate at boundaries)</strong> is violated; each service should validate inputs at its interface rather than assuming internal callers are safe.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Availability over confidentiality</b>: this is a prioritization tradeoff, not the trust-boundary flaw described.</span><span class='qd'><b>Security through obscurity</b>: obscurity concerns hiding design, not input validation between services.</span><span class='qd'><b>Single point of failure elimination</b>: SPOF removal is a resilience concern, not input trust.</span>" },
{ id:"D6-050", domain:6, obj:"6.2", diff:"medium", q:"A team must validate that a web application properly rejects SQL injection, XSS, and other input attacks against the running app. Which combination is MOST appropriate?", options:["Only physical security testing","Only backup restoration testing","DAST plus targeted manual penetration testing","Only account recertification"], answer:2, explain:"<strong>DAST plus targeted manual penetration testing</strong> exercises the running application with automated and human-driven injection attempts, effectively validating input-handling defenses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only physical security testing</b>: physical testing does not evaluate web input handling.</span><span class='qd'><b>Only backup restoration testing</b>: restoration checks recoverability, not injection defenses.</span><span class='qd'><b>Only account recertification</b>: recertification reviews access rights, not application input attacks.</span>" },
{ id:"D6-051", domain:6, obj:"6.2", diff:"hard", q:"Leadership asks why the organization still needs periodic penetration tests if it already runs continuous BAS. What is the BEST justification?", options:["Pen testing adds human creativity to chain novel and business-logic attacks that automated BAS does not model","BAS and pen testing are identical, so keep only one","BAS is only for compliance while pen tests are illegal","Pen testing removes the need for any vulnerability scanning"], answer:0, explain:"<strong>Pen testing adds human creativity to chain novel and business-logic attacks that automated BAS does not model</strong>; skilled testers discover unforeseen paths beyond the pre-scripted techniques BAS replays.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>BAS and pen testing are identical, so keep only one</b>: they are complementary, not identical.</span><span class='qd'><b>BAS is only for compliance while pen tests are illegal</b>: authorized pen testing is legal and BAS is not merely compliance.</span><span class='qd'><b>Pen testing removes the need for any vulnerability scanning</b>: scanning remains valuable for broad, frequent coverage.</span>" },
{ id:"D6-052", domain:6, obj:"6.2", diff:"hard", q:"A tester is engaged to assess an application but is given only login credentials for a standard user account and high-level documentation, not source code. This knowledge level is BEST described as:", options:["Black-box","White-box","Zero-knowledge","Gray-box"], answer:3, explain:"<strong>Gray-box</strong> testing provides partial knowledge such as a user account and general documentation, balancing realism with efficiency between full and no knowledge.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Black-box</b>: black-box provides no credentials or documentation.</span><span class='qd'><b>White-box</b>: white-box would include source code and full internals.</span><span class='qd'><b>Zero-knowledge</b>: zero-knowledge is equivalent to black-box, with no information given.</span>" },
{ id:"D6-053", domain:6, obj:"6.3", diff:"easy", q:"A security team periodically reviews which users have accounts and whether their access is still appropriate. This ongoing account-management activity is BEST described as:", options:["Data classification","Access review / recertification","Penetration testing","Fuzzing"], answer:1, explain:"<strong>Access review / recertification</strong> periodically confirms that accounts and their entitlements remain appropriate, removing access that is no longer justified.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data classification</b>: classification labels data sensitivity, not account appropriateness.</span><span class='qd'><b>Penetration testing</b>: pen testing attacks systems, not entitlement review.</span><span class='qd'><b>Fuzzing</b>: fuzzing tests input handling, unrelated to account management.</span>" },
{ id:"D6-054", domain:6, obj:"6.3", diff:"medium", q:"An account review reveals a user who changed departments six months ago still retains access to their former team's finance system. This finding is a classic example of:", options:["A false positive","A zero-day vulnerability","Privilege creep (access aggregation)","A buffer overflow"], answer:2, explain:"<strong>Privilege creep (access aggregation)</strong> occurs when users accumulate entitlements across roles over time without old access being revoked, which recertification is designed to catch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A false positive</b>: the excess access is real, not a mistaken finding.</span><span class='qd'><b>A zero-day vulnerability</b>: a zero-day is an unknown software flaw, not stale access.</span><span class='qd'><b>A buffer overflow</b>: a buffer overflow is a memory bug, unrelated to entitlements.</span>" },
{ id:"D6-055", domain:6, obj:"6.3", diff:"medium", q:"Leadership periodically reviews the security program's status, decisions, and metrics to steer investments and hold owners accountable. This governance activity is a:", options:["Firewall change","Management review","Penetration test","Vulnerability scan"], answer:1, explain:"<strong>Management review</strong> is the periodic governance forum where leadership evaluates program performance, metrics, and issues to make risk decisions and set direction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Firewall change</b>: a firewall change is a technical operation, not a governance review.</span><span class='qd'><b>Penetration test</b>: a pen test is a technical assessment, not a leadership review.</span><span class='qd'><b>Vulnerability scan</b>: a scan is a technical data-collection activity, not a management forum.</span>" },
{ id:"D6-056", domain:6, obj:"6.3", diff:"medium", q:"A CISO wants a metric that measures how well security is PERFORMING, such as the percentage of systems patched within SLA. Which term BEST describes this metric?", options:["Key Risk Indicator (KRI)","CVE","Key Performance Indicator (KPI)","RTO"], answer:2, explain:"<strong>Key Performance Indicator (KPI)</strong> measures how effectively a process is performing against its objectives, such as patch-within-SLA rates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Key Risk Indicator (KRI)</b>: a KRI signals rising risk exposure, not process performance.</span><span class='qd'><b>CVE</b>: a CVE identifies a specific vulnerability, not a performance metric.</span><span class='qd'><b>RTO</b>: RTO is a recovery time objective, a continuity target, not a performance metric.</span>" },
{ id:"D6-057", domain:6, obj:"6.3", diff:"hard", q:"A CISO wants an EARLY-WARNING metric whose upward trend signals that risk is increasing, such as a rising number of overdue critical patches. This is BEST described as a:", options:["Key Performance Indicator (KPI)","Service Level Agreement (SLA)","Recovery Point Objective (RPO)","Key Risk Indicator (KRI)"], answer:3, explain:"<strong>Key Risk Indicator (KRI)</strong> is a forward-looking metric whose movement warns that risk exposure is rising, prompting action before an incident occurs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Key Performance Indicator (KPI)</b>: a KPI measures current performance, not an early risk signal.</span><span class='qd'><b>Service Level Agreement (SLA)</b>: an SLA is a commitment level, not a risk-trend indicator.</span><span class='qd'><b>Recovery Point Objective (RPO)</b>: RPO defines acceptable data loss, not risk trending.</span>" },
{ id:"D6-058", domain:6, obj:"6.3", diff:"easy", q:"A company writes data to backup media nightly but has never confirmed the backups can be read back. What is the MOST important control to add?", options:["Encrypting the backup labels","Increasing tape rotation speed","Renaming the backup jobs","Periodic backup restoration testing"], answer:3, explain:"<strong>Periodic backup restoration testing</strong> verifies that backups are actually recoverable; a backup that cannot be restored provides no real protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting the backup labels</b>: encrypting labels does not confirm recoverability.</span><span class='qd'><b>Increasing tape rotation speed</b>: rotation speed does not verify data can be read back.</span><span class='qd'><b>Renaming the backup jobs</b>: renaming is cosmetic and proves nothing about restore success.</span>" },
{ id:"D6-059", domain:6, obj:"6.3", diff:"medium", q:"During a disaster recovery test, a team restores last night's backup and finds the database is corrupt and unusable. What did this test PRIMARILY validate?", options:["That backups exist","That the network is fast enough","That users have strong passwords","That backups are actually recoverable and usable, exposing a gap before a real disaster"], answer:3, explain:"<strong>That backups are actually recoverable and usable, exposing a gap before a real disaster</strong> is the value of restoration testing; it revealed the corruption while it could still be fixed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That backups exist</b>: mere existence was already known; the test proved usability, which failed.</span><span class='qd'><b>That the network is fast enough</b>: throughput is not what this test evaluated.</span><span class='qd'><b>That users have strong passwords</b>: password strength is unrelated to backup recoverability.</span>" },
{ id:"D6-060", domain:6, obj:"6.3", diff:"medium", q:"When a new employee is hired, an account is created with only the access their role requires; when they leave, access is promptly removed. Collecting metrics on the timeliness of these events supports which process area?", options:["Cryptographic key ceremony","Fuzz testing","Account management (provisioning/deprovisioning)","Physical penetration testing"], answer:2, explain:"<strong>Account management (provisioning/deprovisioning)</strong> covers timely creation, modification, and removal of access; metrics on how quickly deprovisioning occurs measure its effectiveness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cryptographic key ceremony</b>: key ceremonies manage keys, not user accounts.</span><span class='qd'><b>Fuzz testing</b>: fuzzing tests software inputs, not account lifecycle.</span><span class='qd'><b>Physical penetration testing</b>: physical testing assesses facilities, not account provisioning.</span>" },
{ id:"D6-061", domain:6, obj:"6.3", diff:"hard", q:"A board asks for security metrics that are meaningful to business decision-making. Which set of metrics is MOST appropriate to present at the board level?", options:["Raw counts of blocked firewall packets","Risk-oriented trends tied to business impact, such as time-to-remediate critical risks and residual risk levels","The number of log lines generated daily","The exact CVE numbers of every patched flaw"], answer:1, explain:"<strong>Risk-oriented trends tied to business impact, such as time-to-remediate critical risks and residual risk levels</strong> speak to governance and decision-making, which is what boards need.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Raw counts of blocked firewall packets</b>: packet counts are operational noise without business meaning.</span><span class='qd'><b>The number of log lines generated daily</b>: log volume is not a decision-relevant metric.</span><span class='qd'><b>The exact CVE numbers of every patched flaw</b>: CVE lists are too granular for board consumption.</span>" },
{ id:"D6-062", domain:6, obj:"6.3", diff:"medium", q:"A security process data program collects, among other things, evidence that privileged accounts are reviewed monthly. What is the PRIMARY purpose of gathering such process data?", options:["To increase storage utilization","To slow down operations intentionally","To demonstrate control effectiveness and support management oversight and audits","To replace the need for any controls"], answer:2, explain:"<strong>To demonstrate control effectiveness and support management oversight and audits</strong> is why process data is collected; evidence enables informed decisions and satisfies assurance needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase storage utilization</b>: consuming storage is a side effect, not a purpose.</span><span class='qd'><b>To slow down operations intentionally</b>: data collection is not meant to impede work.</span><span class='qd'><b>To replace the need for any controls</b>: data supports controls; it does not replace them.</span>" },
{ id:"D6-063", domain:6, obj:"6.3", diff:"easy", q:"Which of the following is the BEST example of a Key Risk Indicator (KRI)?", options:["Number of training courses completed","Percentage of critical vulnerabilities open beyond the remediation SLA","Color of the SOC dashboard","Number of employees in the office"], answer:1, explain:"<strong>Percentage of critical vulnerabilities open beyond the remediation SLA</strong> is a KRI because a rising value signals growing risk exposure that warrants attention.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Number of training courses completed</b>: completion counts are activity metrics, not risk indicators.</span><span class='qd'><b>Color of the SOC dashboard</b>: dashboard color is presentation, not a measured risk signal.</span><span class='qd'><b>Number of employees in the office</b>: headcount is unrelated to security risk trending.</span>" },
{ id:"D6-064", domain:6, obj:"6.3", diff:"medium", q:"A management review meeting concludes that a recurring control failure needs a formal owner and deadline. What is the BEST way to ensure follow-through?", options:["Verbally mention it and move on","Wait for the annual audit to raise it again","Record a tracked action item with an assigned owner and due date, reviewed at the next meeting","Delegate it to whoever is least busy"], answer:2, explain:"<strong>Record a tracked action item with an assigned owner and due date, reviewed at the next meeting</strong> creates accountability and closure, a core function of effective management review.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Verbally mention it and move on</b>: unrecorded intentions rarely get done.</span><span class='qd'><b>Wait for the annual audit to raise it again</b>: deferring to audit delays fixing a known issue.</span><span class='qd'><b>Delegate it to whoever is least busy</b>: assigning by availability, not accountability, undermines ownership.</span>" },
{ id:"D6-065", domain:6, obj:"6.3", diff:"hard", q:"An organization reports 100% of servers patched, yet a breach occurs through an unpatched appliance not counted in the metric. What LESSON about security metrics does this illustrate?", options:["Metrics can mislead if scope is incomplete; coverage and data quality must be validated","Metrics are useless and should be abandoned","Only external auditors can produce valid metrics","Patching metrics should be removed entirely"], answer:0, explain:"<strong>Metrics can mislead if scope is incomplete; coverage and data quality must be validated</strong>; the appliance fell outside the counted population, so the metric gave false assurance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Metrics are useless and should be abandoned</b>: metrics remain valuable when their scope is sound.</span><span class='qd'><b>Only external auditors can produce valid metrics</b>: internal teams can produce valid metrics with proper scope.</span><span class='qd'><b>Patching metrics should be removed entirely</b>: the fix is completeness, not removing the metric.</span>" },
{ id:"D6-066", domain:6, obj:"6.3", diff:"medium", q:"A security team wants to reduce dormant accounts. Which process-data metric MOST directly tracks progress on this goal?", options:["Number and age of inactive or orphaned accounts detected and removed","Average CPU utilization","Number of firewalls in the network","Data center temperature"], answer:0, explain:"<strong>Number and age of inactive or orphaned accounts detected and removed</strong> directly measures dormant-account cleanup, showing whether the process is improving.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Average CPU utilization</b>: CPU load is a performance metric unrelated to accounts.</span><span class='qd'><b>Number of firewalls in the network</b>: firewall count does not track dormant accounts.</span><span class='qd'><b>Data center temperature</b>: environmental data is irrelevant to account hygiene.</span>" },
{ id:"D6-067", domain:6, obj:"6.3", diff:"medium", q:"During account management data collection, the team distinguishes between accounts for people and accounts used by applications. Why is special attention given to non-human (service) accounts?", options:["They never need passwords","They cannot be logged","They often have high privileges, are rarely rotated, and are easy to overlook in reviews","They are always more secure than user accounts"], answer:2, explain:"<strong>They often have high privileges, are rarely rotated, and are easy to overlook in reviews</strong>, making service accounts a frequent and high-impact gap that process data must track.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They never need passwords</b>: service accounts do use credentials, which must be managed.</span><span class='qd'><b>They cannot be logged</b>: their activity can and should be logged.</span><span class='qd'><b>They are always more secure than user accounts</b>: they are frequently less well managed, not more secure.</span>" },
{ id:"D6-068", domain:6, obj:"6.3", diff:"easy", q:"How often should critical data backups be tested for restorability, according to good practice?", options:["Never, if the backup job reports success","Only after a real disaster occurs","Periodically on a defined schedule, and after major changes","Only when auditors demand it once every five years"], answer:2, explain:"<strong>Periodically on a defined schedule, and after major changes</strong> ensures backups remain recoverable as systems evolve, catching failures before they matter.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never, if the backup job reports success</b>: a success message does not prove the data restores correctly.</span><span class='qd'><b>Only after a real disaster occurs</b>: testing during a real disaster is far too late.</span><span class='qd'><b>Only when auditors demand it once every five years</b>: five-year gaps leave long windows of unverified backups.</span>" },
{ id:"D6-069", domain:6, obj:"6.3", diff:"hard", q:"A CISO notices that the patch-within-SLA KPI is green but the mean-time-to-detect KRI is worsening. What does this combination MOST likely indicate?", options:["The program is perfect and needs no attention","KPIs and KRIs always move together","Metrics should be discontinued","Performance on one process is strong while a different risk area (detection) is deteriorating and needs investment"], answer:3, explain:"<strong>Performance on one process is strong while a different risk area (detection) is deteriorating and needs investment</strong>; KPIs and KRIs measure different things, and together they reveal where to focus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The program is perfect and needs no attention</b>: a worsening KRI contradicts perfection.</span><span class='qd'><b>KPIs and KRIs always move together</b>: they measure distinct dimensions and can diverge.</span><span class='qd'><b>Metrics should be discontinued</b>: the metrics are doing their job by surfacing a divergence.</span>" },
{ id:"D6-070", domain:6, obj:"6.3", diff:"easy", q:"A security process data program should ensure the data it collects is reliable enough to make decisions. Which quality is MOST essential for that data?", options:["That it looks impressive on a slide","That it is accurate, complete, and consistently collected","That it is generated in the largest possible volume","That only executives can see it"], answer:1, explain:"<strong>That it is accurate, complete, and consistently collected</strong> is essential; unreliable data leads to poor decisions and false assurance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That it looks impressive on a slide</b>: presentation does not make data trustworthy.</span><span class='qd'><b>That it is generated in the largest possible volume</b>: volume without accuracy is noise.</span><span class='qd'><b>That only executives can see it</b>: restricting visibility does not improve data quality.</span>" },
{ id:"D6-071", domain:6, obj:"6.4", diff:"easy", q:"After testing produces raw findings, what should the report do FIRST to be useful to decision-makers?", options:["List every raw tool output verbatim with no interpretation","Analyze and prioritize findings by risk, with clear impact and recommended remediation","Hide the low-severity findings permanently","Delete findings that would embarrass a team"], answer:1, explain:"<strong>Analyze and prioritize findings by risk, with clear impact and recommended remediation</strong> converts raw data into actionable guidance that leaders can use to allocate effort.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>List every raw tool output verbatim with no interpretation</b>: raw dumps overwhelm readers and lack prioritization.</span><span class='qd'><b>Hide the low-severity findings permanently</b>: low findings can matter and should be recorded, not hidden.</span><span class='qd'><b>Delete findings that would embarrass a team</b>: suppressing findings for politics is unethical and dangerous.</span>" },
{ id:"D6-072", domain:6, obj:"6.4", diff:"medium", q:"A penetration test report includes an executive summary and a detailed technical section. Why include BOTH?", options:["Executives need risk and business impact while technical staff need reproduction steps and fixes","To make the report longer","Auditors only read the technical section","It is required to inflate the page count"], answer:0, explain:"<strong>Executives need risk and business impact while technical staff need reproduction steps and fixes</strong>; tailoring content to each audience makes the report actionable at every level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the report longer</b>: length is not the purpose.</span><span class='qd'><b>Auditors only read the technical section</b>: different readers use different sections, so both are needed.</span><span class='qd'><b>It is required to inflate the page count</b>: padding is never a legitimate goal.</span>" },
{ id:"D6-073", domain:6, obj:"6.4", diff:"medium", q:"When multiple critical findings are reported, how should the organization decide the ORDER of remediation?", options:["Alphabetically by system name","By whichever team complains loudest","By risk, considering likelihood, business impact, and exploitability","By the newest finding first, always"], answer:2, explain:"<strong>By risk, considering likelihood, business impact, and exploitability</strong> ensures the most dangerous, most reachable issues are fixed first, maximizing risk reduction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Alphabetically by system name</b>: naming order has no relationship to risk.</span><span class='qd'><b>By whichever team complains loudest</b>: volume of complaint is not a risk measure.</span><span class='qd'><b>By the newest finding first, always</b>: recency alone ignores severity and impact.</span>" },
{ id:"D6-074", domain:6, obj:"6.4", diff:"hard", q:"A critical finding cannot be remediated before a hard business deadline because the fix requires a vendor patch not yet available. What is the MOST appropriate governance action?", options:["Ignore the finding until the patch appears","Remove the finding from the report","Blame the vendor and take no action","Formally document a risk exception/acceptance with compensating controls, an owner, and an expiry"], answer:3, explain:"<strong>Formally document a risk exception/acceptance with compensating controls, an owner, and an expiry</strong> handles unavoidable delay responsibly, ensuring the risk is acknowledged, mitigated, owned, and revisited.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the finding until the patch appears</b>: ignoring leaves risk unmanaged and unowned.</span><span class='qd'><b>Remove the finding from the report</b>: deleting the finding hides real risk.</span><span class='qd'><b>Blame the vendor and take no action</b>: assigning blame does not manage the exposure.</span>" },
{ id:"D6-075", domain:6, obj:"6.4", diff:"medium", q:"An exception to a security policy is granted so a legacy system can keep running an old protocol temporarily. What MUST accompany a well-governed exception?", options:["An indefinite, open-ended approval with no review","Automatic renewal without reassessment","Removal from all risk registers","A defined expiration date, compensating controls, an accountable owner, and periodic review"], answer:3, explain:"<strong>A defined expiration date, compensating controls, an accountable owner, and periodic review</strong> keeps an exception bounded and managed rather than becoming permanent unmanaged risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An indefinite, open-ended approval with no review</b>: open-ended exceptions become forgotten risk.</span><span class='qd'><b>Automatic renewal without reassessment</b>: renewing without review ignores changing conditions.</span><span class='qd'><b>Removal from all risk registers</b>: exceptions should remain visible in the risk register.</span>" },
{ id:"D6-076", domain:6, obj:"6.4", diff:"easy", q:"After remediation is reported complete, what is the BEST way to confirm the vulnerability is truly fixed?", options:["Trust the developer's word","Perform remediation validation (re-test) to verify the issue no longer exists","Close the ticket without checking","Wait for the next annual test"], answer:1, explain:"<strong>Perform remediation validation (re-test) to verify the issue no longer exists</strong> provides evidence the fix worked and did not introduce regressions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the developer's word</b>: unverified claims may be mistaken or incomplete.</span><span class='qd'><b>Close the ticket without checking</b>: closing without validation risks leaving the flaw open.</span><span class='qd'><b>Wait for the next annual test</b>: waiting a year leaves exposure unverified.</span>" },
{ id:"D6-077", domain:6, obj:"6.4", diff:"medium", q:"A report lists a finding rated 'High' by CVSS, but the affected system holds no sensitive data and is isolated. How should the analyst FINALIZE the risk rating?", options:["Adjust to an organizational risk rating that factors in real business context and exposure","Keep the raw CVSS score unchanged regardless of context","Automatically downgrade every High to Low","Escalate every finding to Critical"], answer:0, explain:"<strong>Adjust to an organizational risk rating that factors in real business context and exposure</strong> because CVSS is a starting severity that should be contextualized to the environment for accurate prioritization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep the raw CVSS score unchanged regardless of context</b>: raw scores ignore local context like data sensitivity and isolation.</span><span class='qd'><b>Automatically downgrade every High to Low</b>: blanket downgrades are as wrong as blanket keeps.</span><span class='qd'><b>Escalate every finding to Critical</b>: inflating all findings destroys prioritization.</span>" },
{ id:"D6-078", domain:6, obj:"6.4", diff:"hard", q:"A CISO receives a pen test report where the tester rated everything 'Critical' to be safe. What is the PRIMARY problem with this reporting approach?", options:["It makes the report shorter","Over-rating destroys the ability to prioritize, so real critical issues get lost in the noise","It guarantees faster remediation of all items","It removes the need for an executive summary"], answer:1, explain:"<strong>Over-rating destroys the ability to prioritize, so real critical issues get lost in the noise</strong>; if everything is critical, nothing is, and limited resources are misallocated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the report shorter</b>: rating does not affect length.</span><span class='qd'><b>It guarantees faster remediation of all items</b>: flooding teams with criticals slows, not speeds, meaningful fixes.</span><span class='qd'><b>It removes the need for an executive summary</b>: a summary is still needed regardless of ratings.</span>" },
{ id:"D6-079", domain:6, obj:"6.4", diff:"medium", q:"A remediation plan should include target dates and owners. Which artifact commonly tracks findings, owners, and deadlines to closure?", options:["A network topology map","A Plan of Action and Milestones (POA&M)","A data classification matrix","A cryptographic key inventory"], answer:1, explain:"<strong>A Plan of Action and Milestones (POA&M)</strong> tracks each finding with a responsible owner, remediation steps, and target completion dates through to closure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A network topology map</b>: a topology map shows architecture, not remediation tracking.</span><span class='qd'><b>A data classification matrix</b>: a classification matrix labels data, not findings.</span><span class='qd'><b>A cryptographic key inventory</b>: a key inventory lists keys, not remediation items.</span>" },
{ id:"D6-080", domain:6, obj:"6.4", diff:"medium", q:"During analysis, a scanner and a manual test disagree about whether a flaw is exploitable. What is the BEST way to resolve the discrepancy before reporting?", options:["Validate manually to confirm exploitability and report the verified conclusion with evidence","Always trust the automated scanner","Report both as separate unrelated findings","Discard both findings"], answer:0, explain:"<strong>Validate manually to confirm exploitability and report the verified conclusion with evidence</strong> resolves the conflict with proof, avoiding both false positives and false negatives in the report.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always trust the automated scanner</b>: scanners produce false positives that manual validation catches.</span><span class='qd'><b>Report both as separate unrelated findings</b>: they concern the same flaw and should be reconciled.</span><span class='qd'><b>Discard both findings</b>: discarding may drop a real vulnerability.</span>" },
{ id:"D6-081", domain:6, obj:"6.4", diff:"hard", q:"An organization keeps granting the same policy exception every year without ever fixing the underlying issue. What does this recurring exception MOST likely indicate to a risk owner?", options:["Accumulating unmanaged risk and a need to address root cause or formally accept it at the right level","The exception process is working perfectly","That exceptions should never be reviewed","That the finding was invalid"], answer:0, explain:"<strong>Accumulating unmanaged risk and a need to address root cause or formally accept it at the right level</strong>; perpetual exceptions are a red flag that a real fix or a documented, authority-level acceptance is overdue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The exception process is working perfectly</b>: perpetual renewal signals a problem, not success.</span><span class='qd'><b>That exceptions should never be reviewed</b>: review is exactly what surfaces this pattern.</span><span class='qd'><b>That the finding was invalid</b>: repeated exceptions imply the finding is real and unaddressed.</span>" },
{ id:"D6-082", domain:6, obj:"6.4", diff:"easy", q:"Which element makes a security finding in a report ACTIONABLE for the team that must fix it?", options:["A vague statement that 'security is weak'","Only the CVE number","Only an executive opinion","A clear description, evidence, risk rating, and specific remediation recommendation"], answer:3, explain:"<strong>A clear description, evidence, risk rating, and specific remediation recommendation</strong> gives the team what it needs to understand, prioritize, and fix the issue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A vague statement that 'security is weak'</b>: vagueness gives no path to remediation.</span><span class='qd'><b>Only the CVE number</b>: a CVE alone lacks context and remediation guidance.</span><span class='qd'><b>Only an executive opinion</b>: opinion without evidence and steps is not actionable.</span>" },
{ id:"D6-083", domain:6, obj:"6.4", diff:"medium", q:"After a report is delivered, a finding's risk is deemed low enough that the business chooses to live with it rather than spend to fix it. This decision is BEST described as:", options:["Risk avoidance","Risk transfer","Risk elimination","Risk acceptance"], answer:3, explain:"<strong>Risk acceptance</strong> is a deliberate decision by an appropriate authority to tolerate a risk without further mitigation, typically when cost outweighs benefit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk avoidance</b>: avoidance stops the risky activity entirely, which is not the case here.</span><span class='qd'><b>Risk transfer</b>: transfer shifts risk to a third party such as an insurer.</span><span class='qd'><b>Risk elimination</b>: risk cannot be fully eliminated, and no mitigation is being applied here.</span>" },
{ id:"D6-084", domain:6, obj:"6.4", diff:"medium", q:"A report must be distributed containing detailed exploit steps against production systems. What handling requirement is MOST important?", options:["Post it on the public intranet for transparency","Classify and restrict the report to authorized recipients due to its sensitivity","Email it to all staff for awareness","Attach it to the public audit portal"], answer:1, explain:"<strong>Classify and restrict the report to authorized recipients due to its sensitivity</strong>; a report detailing live exploit paths is a roadmap for attackers and must be tightly controlled.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Post it on the public intranet for transparency</b>: broad internal posting exposes exploit details unnecessarily.</span><span class='qd'><b>Email it to all staff for awareness</b>: mass distribution defeats need-to-know.</span><span class='qd'><b>Attach it to the public audit portal</b>: public exposure of exploit steps is dangerous.</span>" },
{ id:"D6-085", domain:6, obj:"6.4", diff:"hard", q:"Analysis shows five separate findings all stem from the same missing input-validation library. What is the MOST efficient remediation strategy?", options:["Fix each of the five findings with unrelated one-off patches","Accept all five as separate risks","Report them but recommend no fix","Address the common root cause once so all five findings are resolved together"], answer:3, explain:"<strong>Address the common root cause once so all five findings are resolved together</strong> is more efficient and durable than five isolated fixes, and it prevents recurrence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fix each of the five findings with unrelated one-off patches</b>: piecemeal fixes are wasteful and may leave the root cause active.</span><span class='qd'><b>Accept all five as separate risks</b>: accepting fixable systemic risk is imprudent.</span><span class='qd'><b>Report them but recommend no fix</b>: reporting without recommending the obvious root-cause fix fails the reader.</span>" },
{ id:"D6-086", domain:6, obj:"6.4", diff:"medium", q:"A remediation validation re-test confirms the original flaw is fixed but reveals the fix broke a related feature. What should the report note?", options:["Only that the original flaw is fixed","Both that the flaw is remediated and that a regression was introduced requiring follow-up","Nothing, since the flaw is closed","That testing should stop to avoid finding more issues"], answer:1, explain:"<strong>Both that the flaw is remediated and that a regression was introduced requiring follow-up</strong> gives a complete, honest picture so the new problem is tracked rather than ignored.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only that the original flaw is fixed</b>: omitting the regression hides a new issue.</span><span class='qd'><b>Nothing, since the flaw is closed</b>: silence leaves the regression unaddressed.</span><span class='qd'><b>That testing should stop to avoid finding more issues</b>: stopping to avoid findings is the opposite of good assurance.</span>" },
{ id:"D6-087", domain:6, obj:"6.5", diff:"easy", q:"An audit is performed by the organization's own staff to evaluate its controls for internal improvement. This is BEST described as a(n):", options:["External audit","Internal audit","Third-party audit","Regulatory seizure"], answer:1, explain:"<strong>Internal audit</strong> is conducted by the organization's own (ideally independent) audit function to evaluate and improve controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>External audit</b>: an external audit is performed by an outside firm, not internal staff.</span><span class='qd'><b>Third-party audit</b>: a third-party audit is conducted by an independent external party, often for attestation.</span><span class='qd'><b>Regulatory seizure</b>: seizure is a legal enforcement action, not an audit.</span>" },
{ id:"D6-088", domain:6, obj:"6.5", diff:"medium", q:"A customer wants independent assurance about a SaaS provider's controls without conducting its own audit of the provider. The provider commissions an audit and shares the resulting report. This is BEST described as a:", options:["Internal self-assessment","Third-party (independent) audit and attestation report","Penetration test","Vulnerability scan"], answer:1, explain:"<strong>Third-party (independent) audit and attestation report</strong> lets many customers gain assurance from one independent examination of the provider's controls rather than each auditing separately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Internal self-assessment</b>: a self-assessment lacks the independence customers seek.</span><span class='qd'><b>Penetration test</b>: a pen test evaluates exploitability, not a control attestation for customers.</span><span class='qd'><b>Vulnerability scan</b>: a scan lists flaws and is not an independent control attestation.</span>" },
{ id:"D6-089", domain:6, obj:"6.5", diff:"easy", q:"A prospective customer's auditors ask for a SOC report they can review under NDA that details the provider's controls and the auditor's tests and results relevant to security and availability. Which report type fits?", options:["SOC 1","SOC 3","SOC 2","PCI SAQ"], answer:2, explain:"<strong>SOC 2</strong> reports address the trust services criteria (security, availability, processing integrity, confidentiality, privacy) and are restricted-use reports shared under NDA with detailed control descriptions and test results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SOC 1</b>: SOC 1 focuses on controls relevant to financial reporting (ICFR), not general security trust criteria.</span><span class='qd'><b>SOC 3</b>: SOC 3 is a public, general-use summary without the detailed test results.</span><span class='qd'><b>PCI SAQ</b>: a PCI Self-Assessment Questionnaire concerns card data compliance, not a SOC attestation.</span>" },
{ id:"D6-090", domain:6, obj:"6.5", diff:"hard", q:"A SaaS provider wants a freely shareable, public-facing seal-style report attesting to its security controls without disclosing sensitive control details. Which SOC report is MOST appropriate?", options:["SOC 1 Type II","SOC 2 Type II","SOC 3","An internal audit memo"], answer:2, explain:"<strong>SOC 3</strong> is a general-use, public report that provides an auditor's opinion on trust services controls without the detailed testing that SOC 2 exposes, making it suitable for public distribution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SOC 1 Type II</b>: SOC 1 addresses financial-reporting controls and is restricted-use, not a public security seal.</span><span class='qd'><b>SOC 2 Type II</b>: SOC 2 is detailed and restricted-use, shared under NDA rather than publicly.</span><span class='qd'><b>An internal audit memo</b>: an internal memo is not an independent, shareable attestation.</span>" },
{ id:"D6-091", domain:6, obj:"6.5", diff:"medium", q:"An organization must distinguish SOC 1 from SOC 2. Which statement is CORRECT?", options:["SOC 1 is public while SOC 2 is always secret","SOC 1 covers privacy only and SOC 2 covers finance only","SOC 1 and SOC 2 are identical reports with different names","SOC 1 addresses controls relevant to financial reporting, while SOC 2 addresses trust services criteria such as security and availability"], answer:3, explain:"<strong>SOC 1 addresses controls relevant to financial reporting, while SOC 2 addresses trust services criteria such as security and availability</strong> correctly captures the scope difference between the two reports.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SOC 1 is public while SOC 2 is always secret</b>: both SOC 1 and SOC 2 are restricted-use; SOC 3 is the public report.</span><span class='qd'><b>SOC 1 covers privacy only and SOC 2 covers finance only</b>: this reverses and misstates their scopes.</span><span class='qd'><b>SOC 1 and SOC 2 are identical reports with different names</b>: they address different control objectives.</span>" },
{ id:"D6-092", domain:6, obj:"6.5", diff:"hard", q:"A customer needs assurance that a provider's controls not only were suitably designed but also operated EFFECTIVELY over a review period of several months. Which SOC report variant provides this?", options:["A Type I report","A SOC 3 seal only","A vulnerability scan report","A Type II report"], answer:3, explain:"<strong>A Type II report</strong> evaluates both the design and the operating effectiveness of controls over a defined period, giving stronger assurance than a point-in-time review.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A Type I report</b>: a Type I report assesses design suitability at a single point in time, not operating effectiveness over months.</span><span class='qd'><b>A SOC 3 seal only</b>: a SOC 3 is a summary attestation and does not provide the detailed period-of-time testing evidence.</span><span class='qd'><b>A vulnerability scan report</b>: a scan lists technical flaws and is not a control-attestation report.</span>" },
{ id:"D6-093", domain:6, obj:"6.5", diff:"easy", q:"Regulators require an INDEPENDENT external audit of a bank's financial and security controls. What is the PRIMARY advantage of using an external auditor over an internal one for this purpose?", options:["External auditors are always cheaper","Internal auditors cannot examine controls at all","External auditors provide greater independence and credibility to outside stakeholders","External auditors never need evidence"], answer:2, explain:"<strong>External auditors provide greater independence and credibility to outside stakeholders</strong> such as regulators and investors, because they are not part of the organization being examined.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>External auditors are always cheaper</b>: external audits are often more expensive, not cheaper.</span><span class='qd'><b>Internal auditors cannot examine controls at all</b>: internal audit does examine controls, just with less external independence.</span><span class='qd'><b>External auditors never need evidence</b>: all auditors rely on evidence.</span>" },
{ id:"D6-094", domain:6, obj:"6.5", diff:"medium", q:"A vendor refuses to let its customers perform their own on-site audits, citing many customer requests. Which approach BEST satisfies customers' assurance needs while limiting disruption to the vendor?", options:["Provide an independent third-party audit report (e.g., SOC 2) that customers can review","Ban all audits entirely","Let every customer audit on the same day","Replace audits with a marketing brochure"], answer:0, explain:"<strong>Provide an independent third-party audit report (e.g., SOC 2) that customers can review</strong> gives many customers credible assurance from one examination, reducing repeated on-site audits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ban all audits entirely</b>: banning assurance would drive customers away and fail due diligence.</span><span class='qd'><b>Let every customer audit on the same day</b>: mass simultaneous audits are more disruptive, not less.</span><span class='qd'><b>Replace audits with a marketing brochure</b>: a brochure is not independent assurance.</span>" },
{ id:"D6-095", domain:6, obj:"6.5", diff:"easy", q:"An auditor gathers logs, configuration exports, and screenshots to support each finding. In an audit, this material is BEST described as:", options:["Marketing collateral","A threat model","A network baseline","Audit evidence"], answer:3, explain:"<strong>Audit evidence</strong> is the objective, verifiable material an auditor collects to support conclusions about whether controls are designed and operating as intended.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Marketing collateral</b>: marketing material is promotional, not verifiable audit support.</span><span class='qd'><b>A threat model</b>: a threat model analyzes potential attacks, not audit findings support.</span><span class='qd'><b>A network baseline</b>: a baseline is a reference configuration, not audit evidence by itself.</span>" },
{ id:"D6-096", domain:6, obj:"6.5", diff:"hard", q:"During a third-party audit, the assessor discovers the organization's internal audit team reports directly to the CIO whose systems it audits. Why is this a concern?", options:["It improves independence","It has no impact on audit quality","It is required by every framework","It creates a conflict of interest that undermines audit independence and objectivity"], answer:3, explain:"<strong>It creates a conflict of interest that undermines audit independence and objectivity</strong>; auditors reporting to the owner of the systems they assess may be pressured to soften findings, so independent reporting lines (e.g., to the board or audit committee) are preferred.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It improves independence</b>: reporting to the audited party reduces, not improves, independence.</span><span class='qd'><b>It has no impact on audit quality</b>: compromised independence directly threatens audit quality.</span><span class='qd'><b>It is required by every framework</b>: frameworks call for audit independence, not reporting to the audited executive.</span>" },
{ id:"D6-097", domain:6, obj:"6.5", diff:"medium", q:"An organization is preparing for a formal external audit. What is the BEST action to take BEFORE the auditors arrive?", options:["Conduct an internal readiness review to identify and remediate gaps against the audit criteria","Delete logs that might show past problems","Tell staff to refuse to answer auditor questions","Disable monitoring so nothing is recorded"], answer:0, explain:"<strong>Conduct an internal readiness review to identify and remediate gaps against the audit criteria</strong> lets the organization fix issues proactively and enter the audit prepared and honest.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete logs that might show past problems</b>: destroying evidence is unethical and likely illegal.</span><span class='qd'><b>Tell staff to refuse to answer auditor questions</b>: obstruction undermines the audit and trust.</span><span class='qd'><b>Disable monitoring so nothing is recorded</b>: disabling controls to hide gaps is deceptive and harmful.</span>" },
{ id:"D6-098", domain:6, obj:"6.5", diff:"easy", q:"A SaaS buyer's security team receives a provider's SOC 2 Type II report during vendor due diligence. What should the buyer do with it?", options:["Assume the vendor is fully secure and skip further review","Review the scope, testing period, exceptions, and any noted deviations to inform the risk decision","File it without reading it","Publish it publicly to demonstrate transparency"], answer:1, explain:"<strong>Review the scope, testing period, exceptions, and any noted deviations to inform the risk decision</strong> is the proper use; the report is an input to due diligence, not a rubber stamp.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the vendor is fully secure and skip further review</b>: a report does not guarantee security or cover every concern.</span><span class='qd'><b>File it without reading it</b>: ignoring the content wastes the assurance it offers.</span><span class='qd'><b>Publish it publicly to demonstrate transparency</b>: SOC 2 is restricted-use and should not be published; SOC 3 is the public option.</span>" },
{ id:"D6-099", domain:6, obj:"6.5", diff:"hard", q:"An organization operates in a highly regulated industry and must decide who conducts its recurring compliance audits. Which arrangement BEST balances cost, independence, and regulatory acceptance?", options:["Only self-assessments performed by the system owners","External auditors performing every routine check daily","A combination of internal audits for continuous improvement and periodic independent external audits for regulatory attestation","No audits, relying solely on the vendor's word"], answer:2, explain:"<strong>A combination of internal audits for continuous improvement and periodic independent external audits for regulatory attestation</strong> leverages internal audit for frequent, cost-effective coverage while external audits deliver the independence regulators require.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only self-assessments performed by the system owners</b>: self-assessment alone lacks the independence regulators expect.</span><span class='qd'><b>External auditors performing every routine check daily</b>: daily external audits are prohibitively costly and unnecessary.</span><span class='qd'><b>No audits, relying solely on the vendor's word</b>: unverified assurance fails regulatory and due-diligence obligations.</span>" },
{ id:"D6-100", domain:6, obj:"6.5", diff:"easy", q:"Which SOC report is intended for a GENERAL, public audience and is often displayed as a trust seal on a company website?", options:["SOC 1 Type I","SOC 3","SOC 2 Type II","A penetration test report"], answer:1, explain:"<strong>SOC 3</strong> is designed for general public distribution and is commonly used as a trust seal because it summarizes assurance without exposing sensitive control detail.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SOC 1 Type I</b>: SOC 1 concerns financial-reporting controls and is restricted-use.</span><span class='qd'><b>SOC 2 Type II</b>: SOC 2 is detailed and restricted-use, shared under NDA.</span><span class='qd'><b>A penetration test report</b>: a pen test report is a technical finding document, not a public SOC attestation.</span>" }
);
